ALTER TYPE "MarketStatus" RENAME TO "MarketStatus_old";
CREATE TYPE "MarketStatus" AS ENUM ('DRAFT','ACTIVE','CLOSED','RESOLUTION_READY','RESOLVED','VOID');
ALTER TABLE "Market" ALTER COLUMN "status" DROP DEFAULT;
ALTER TABLE "Market" ALTER COLUMN "status" TYPE "MarketStatus" USING (CASE WHEN "status"::text IN ('OPEN','SUSPENDED') THEN 'ACTIVE' ELSE "status"::text END)::"MarketStatus";
ALTER TABLE "Market" ALTER COLUMN "status" SET DEFAULT 'DRAFT';
DROP TYPE "MarketStatus_old";
UPDATE "MarketOutcome" SET "key"='OVER' WHERE "key"='OVER_2_5';
UPDATE "MarketOutcome" SET "key"='UNDER' WHERE "key"='UNDER_2_5';
ALTER TYPE "ProofStatus" RENAME TO "ProofStatus_old";
CREATE TYPE "ProofStatus" AS ENUM ('NOT_REQUESTED','VERIFIED','FAILED');
ALTER TABLE "ResolutionReceipt" ALTER COLUMN "proofStatus" DROP DEFAULT;
ALTER TABLE "ResolutionReceipt" ALTER COLUMN "proofStatus" TYPE "ProofStatus" USING (CASE WHEN "proofStatus"::text='PENDING' THEN 'NOT_REQUESTED' ELSE "proofStatus"::text END)::"ProofStatus";
ALTER TABLE "ResolutionReceipt" ALTER COLUMN "proofStatus" SET DEFAULT 'NOT_REQUESTED';
DROP TYPE "ProofStatus_old";
CREATE TYPE "QuoteSource" AS ENUM ('SYNTHETIC','ADMIN_DEMO','TXLINE');
CREATE TYPE "LedgerEntryType" AS ENUM ('SESSION_GRANT','POSITION_PURCHASE','SETTLEMENT_PAYOUT','VOID_REFUND','ADMIN_RESET');
ALTER TABLE "Market" ADD COLUMN "displayOrder" INTEGER NOT NULL DEFAULT 0, ADD COLUMN "closeAt" TIMESTAMP(3), ADD COLUMN "settlementStatus" "SettlementStatus" NOT NULL DEFAULT 'PENDING';
UPDATE "Market" m SET "closeAt" = f."startsAt" FROM "Fixture" f WHERE f.id=m."fixtureId";
ALTER TABLE "Market" ALTER COLUMN "closeAt" SET NOT NULL;
ALTER TABLE "ResolutionReceipt" ADD COLUMN "fixtureId" TEXT, ADD COLUMN "ruleVersion" TEXT, ADD COLUMN "finalObservationId" TEXT, ADD COLUMN "providerSequence" INTEGER, ADD COLUMN "providerTimestamp" TIMESTAMP(3), ADD COLUMN "sourceMode" "SourceMode", ADD COLUMN "scoreAction" TEXT, ADD COLUMN "participant1Goals" INTEGER, ADD COLUMN "participant2Goals" INTEGER, ADD COLUMN "participant1IsHome" BOOLEAN, ADD COLUMN "resolutionStatus" TEXT, ADD COLUMN "integrityDigest" TEXT;
CREATE UNIQUE INDEX "ResolutionReceipt_integrityDigest_key" ON "ResolutionReceipt"("integrityDigest");
CREATE TABLE "AnonymousSession" ("id" TEXT NOT NULL, "tokenHash" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "lastSeenAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "revokedAt" TIMESTAMP(3), CONSTRAINT "AnonymousSession_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "AnonymousSession_tokenHash_key" ON "AnonymousSession"("tokenHash");
CREATE TABLE "DemoAccount" ("id" TEXT NOT NULL, "sessionId" TEXT, "label" TEXT, "availableCredits" INTEGER NOT NULL DEFAULT 0, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "DemoAccount_pkey" PRIMARY KEY ("id"), CONSTRAINT "DemoAccount_balance_guard" CHECK ("availableCredits" >= 0));
CREATE UNIQUE INDEX "DemoAccount_sessionId_key" ON "DemoAccount"("sessionId"); CREATE INDEX "DemoAccount_availableCredits_idx" ON "DemoAccount"("availableCredits");
CREATE TABLE "CreditLedgerEntry" ("id" TEXT NOT NULL, "accountId" TEXT NOT NULL, "amount" INTEGER NOT NULL, "entryType" "LedgerEntryType" NOT NULL, "reference" TEXT NOT NULL, "marketId" TEXT, "positionId" TEXT, "receiptId" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "CreditLedgerEntry_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "CreditLedgerEntry_reference_key" ON "CreditLedgerEntry"("reference"); CREATE INDEX "CreditLedgerEntry_accountId_createdAt_idx" ON "CreditLedgerEntry"("accountId","createdAt");
CREATE TABLE "OutcomeQuote" ("id" TEXT NOT NULL, "marketId" TEXT NOT NULL, "outcomeId" TEXT NOT NULL, "version" INTEGER NOT NULL, "priceBasisPoints" INTEGER NOT NULL, "source" "QuoteSource" NOT NULL, "active" BOOLEAN NOT NULL DEFAULT true, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "OutcomeQuote_pkey" PRIMARY KEY ("id"), CONSTRAINT "OutcomeQuote_price_guard" CHECK ("priceBasisPoints" > 0 AND "priceBasisPoints" <= 10000));
CREATE UNIQUE INDEX "OutcomeQuote_marketId_outcomeId_version_key" ON "OutcomeQuote"("marketId","outcomeId","version"); CREATE INDEX "OutcomeQuote_marketId_active_idx" ON "OutcomeQuote"("marketId","active");
CREATE TABLE "DemoPurchase" ("id" TEXT NOT NULL, "accountId" TEXT NOT NULL, "marketId" TEXT NOT NULL, "outcomeId" TEXT NOT NULL, "idempotencyKey" TEXT NOT NULL, "stakeCredits" INTEGER NOT NULL, "quoteVersion" INTEGER NOT NULL, "priceBasisPoints" INTEGER NOT NULL, "sharesMicros" BIGINT NOT NULL, "potentialPayoutCredits" INTEGER NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "DemoPurchase_pkey" PRIMARY KEY ("id"), CONSTRAINT "DemoPurchase_stake_guard" CHECK ("stakeCredits" > 0));
CREATE UNIQUE INDEX "DemoPurchase_accountId_idempotencyKey_key" ON "DemoPurchase"("accountId","idempotencyKey"); CREATE INDEX "DemoPurchase_marketId_createdAt_idx" ON "DemoPurchase"("marketId","createdAt");
CREATE TABLE "DemoPosition" ("id" TEXT NOT NULL, "accountId" TEXT NOT NULL, "marketId" TEXT NOT NULL, "outcomeId" TEXT NOT NULL, "stakeCredits" INTEGER NOT NULL, "sharesMicros" BIGINT NOT NULL, "potentialPayoutCredits" INTEGER NOT NULL, "actualPayoutCredits" INTEGER, "settledAt" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "DemoPosition_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "DemoPosition_accountId_marketId_outcomeId_key" ON "DemoPosition"("accountId","marketId","outcomeId"); CREATE INDEX "DemoPosition_accountId_settledAt_idx" ON "DemoPosition"("accountId","settledAt");
CREATE TABLE "MarketLifecycleAudit" ("id" TEXT NOT NULL, "marketId" TEXT NOT NULL, "previousStatus" "MarketStatus" NOT NULL, "newStatus" "MarketStatus" NOT NULL, "reasonCode" TEXT NOT NULL, "actorType" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "MarketLifecycleAudit_pkey" PRIMARY KEY ("id")); CREATE INDEX "MarketLifecycleAudit_marketId_createdAt_idx" ON "MarketLifecycleAudit"("marketId","createdAt");
ALTER TABLE "DemoAccount" ADD CONSTRAINT "DemoAccount_sessionId_fkey" FOREIGN KEY ("sessionId") REFERENCES "AnonymousSession"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "CreditLedgerEntry" ADD CONSTRAINT "CreditLedgerEntry_accountId_fkey" FOREIGN KEY ("accountId") REFERENCES "DemoAccount"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "OutcomeQuote" ADD CONSTRAINT "OutcomeQuote_marketId_fkey" FOREIGN KEY ("marketId") REFERENCES "Market"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "OutcomeQuote" ADD CONSTRAINT "OutcomeQuote_outcomeId_fkey" FOREIGN KEY ("outcomeId") REFERENCES "MarketOutcome"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "DemoPurchase" ADD CONSTRAINT "DemoPurchase_accountId_fkey" FOREIGN KEY ("accountId") REFERENCES "DemoAccount"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "DemoPurchase" ADD CONSTRAINT "DemoPurchase_marketId_fkey" FOREIGN KEY ("marketId") REFERENCES "Market"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "DemoPurchase" ADD CONSTRAINT "DemoPurchase_outcomeId_fkey" FOREIGN KEY ("outcomeId") REFERENCES "MarketOutcome"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "DemoPosition" ADD CONSTRAINT "DemoPosition_accountId_fkey" FOREIGN KEY ("accountId") REFERENCES "DemoAccount"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "DemoPosition" ADD CONSTRAINT "DemoPosition_marketId_fkey" FOREIGN KEY ("marketId") REFERENCES "Market"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "DemoPosition" ADD CONSTRAINT "DemoPosition_outcomeId_fkey" FOREIGN KEY ("outcomeId") REFERENCES "MarketOutcome"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "MarketLifecycleAudit" ADD CONSTRAINT "MarketLifecycleAudit_marketId_fkey" FOREIGN KEY ("marketId") REFERENCES "Market"("id") ON DELETE CASCADE ON UPDATE CASCADE;
